## 2. useForm の基本設定

### 2-1. TypeScript と defaultValues を必ず設定する

```tsx
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const LoginSchema = z.object({
  email: z.email('有効なメールアドレスを入力してください'),
  password: z.string().min(8, 'パスワードは8文字以上必要です'),
  rememberMe: z.boolean().default(false),
});

type LoginFormValues = z.infer<typeof LoginSchema>;

function LoginForm() {
  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
    reset,
  } = useForm<LoginFormValues>({
    resolver: zodResolver(LoginSchema),
    // ✅ defaultValues は必ず設定する（undefined を避け、型を整合させる）
    defaultValues: {
      email: '',
      password: '',
      rememberMe: false,
    },
    mode: 'onBlur',
  });

  const onSubmit = async (data: LoginFormValues) => {
    // data は型付き + バリデーション済み
    await login(data);
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <input {...register('email')} type="email" />
      {errors.email && <p role="alert">{errors.email.message}</p>}

      <input {...register('password')} type="password" />
      {errors.password && <p role="alert">{errors.password.message}</p>}

      <input {...register('rememberMe')} type="checkbox" />

      <button type="submit" disabled={isSubmitting}>
        {isSubmitting ? 'ログイン中...' : 'ログイン'}
      </button>
    </form>
  );
}
```

---

### 2-2. 既存データの編集フォーム（async defaultValues）

```tsx
function EditUserForm({ userId }: { userId: number }) {
  const { data: user } = useQuery(['user', userId], () => fetchUser(userId));

  const form = useForm<UserFormValues>({
    resolver: zodResolver(UserFormSchema),
    // ✅ データ取得後に reset() で値を注入するのが基本パターン
    defaultValues: {
      name: '',
      email: '',
      bio: '',
    },
  });

  // データが取得できたら reset で既存値をセット
  useEffect(() => {
    if (user) {
      form.reset({
        name: user.name,
        email: user.email,
        bio: user.bio ?? '',
      });
    }
  }, [user, form.reset]); // ✅ form.reset を依存配列に（form オブジェクト全体ではない）

  // ...
}
```

