## 4. register vs Controller の使い分け

### register — ネイティブ HTML 要素に使う（推奨）

```tsx
// ✅ ネイティブ input / select / textarea は register を使う
<input {...register('email')} type="email" />
<select {...register('role')}>
  <option value="user">ユーザー</option>
  <option value="admin">管理者</option>
</select>
<textarea {...register('bio')} />
```

---

### Controller — 外部 UI ライブラリ・制御コンポーネントに使う

```tsx
import { Controller } from 'react-hook-form';
import { DatePicker } from '@mui/x-date-pickers';
import Select from 'react-select';

// ✅ 制御コンポーネント（value/onChange が必要なもの）は Controller
function MyForm() {
  const { control } = useForm<FormValues>({ ... });

  return (
    <>
      {/* MUI DatePicker */}
      <Controller
        name="birthDate"
        control={control}
        render={({ field, fieldState }) => (
          <DatePicker
            value={field.value}
            onChange={field.onChange}
            onClose={field.onBlur}
            slotProps={{
              textField: {
                error: !!fieldState.error,
                helperText: fieldState.error?.message,
              },
            }}
          />
        )}
      />

      {/* react-select */}
      <Controller
        name="tags"
        control={control}
        render={({ field }) => (
          <Select
            {...field}
            isMulti
            options={tagOptions}
          />
        )}
      />
    </>
  );
}
```

---

### useController — カスタムフィールドコンポーネントの内部で使う

```tsx
// ✅ 再利用可能な入力コンポーネントを作る場合は useController
import { useController, Control, FieldPath, FieldValues } from 'react-hook-form';

interface TextFieldProps<T extends FieldValues> {
  name: FieldPath<T>;
  control: Control<T>;
  label: string;
  placeholder?: string;
}

function TextField<T extends FieldValues>({
  name,
  control,
  label,
  placeholder,
}: TextFieldProps<T>) {
  const {
    field,
    fieldState: { error },
  } = useController({ name, control });

  return (
    <div>
      <label htmlFor={name}>{label}</label>
      <input
        {...field}
        id={name}
        placeholder={placeholder}
        aria-invalid={!!error}
        aria-describedby={error ? `${name}-error` : undefined}
      />
      {error && (
        <p id={`${name}-error`} role="alert">
          {error.message}
        </p>
      )}
    </div>
  );
}
```

