## 6. FormProvider / useFormContext でのコンポーネント分割

### 大きなフォームはコンテキストで分割する

```tsx
// forms/UserProfileForm.tsx — フォームのルート
import { useForm, FormProvider } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { UserProfileSchema, type UserProfileValues } from '@/schemas/forms/userProfile';
import { BasicInfoSection } from './sections/BasicInfoSection';
import { AddressSection } from './sections/AddressSection';
import { NotificationSection } from './sections/NotificationSection';

export function UserProfileForm() {
  const methods = useForm<UserProfileValues>({
    resolver: zodResolver(UserProfileSchema),
    defaultValues: { /* ... */ },
  });

  const onSubmit = async (data: UserProfileValues) => {
    await updateUserProfile(data);
  };

  return (
    // ✅ FormProvider で全メソッドをコンテキストに流す
    <FormProvider {...methods}>
      <form onSubmit={methods.handleSubmit(onSubmit)}>
        <BasicInfoSection />
        <AddressSection />
        <NotificationSection />
        <button type="submit" disabled={methods.formState.isSubmitting}>
          保存する
        </button>
      </form>
    </FormProvider>
  );
}
```

```tsx
// forms/sections/BasicInfoSection.tsx — 子コンポーネント（props なし）
import { useFormContext } from 'react-hook-form';
import type { UserProfileValues } from '@/schemas/forms/userProfile';

export function BasicInfoSection() {
  // ✅ useFormContext でコンテキストからメソッドを取得（props drilling なし）
  const { register, formState: { errors } } = useFormContext<UserProfileValues>();

  return (
    <section>
      <h2>基本情報</h2>
      <div>
        <label htmlFor="name">名前</label>
        <input {...register('name')} id="name" />
        {errors.name && <p role="alert">{errors.name.message}</p>}
      </div>
      <div>
        <label htmlFor="email">メールアドレス</label>
        <input {...register('email')} id="email" type="email" />
        {errors.email && <p role="alert">{errors.email.message}</p>}
      </div>
    </section>
  );
}
```

---

### FormProvider 内では useFormState でエラーを購読する

```tsx
// ❌ Bad: useFormContext から formState を分割代入すると全変化で再レンダリング
function SomeField() {
  const { register, formState: { errors } } = useFormContext(); // 非推奨
}

// ✅ Good: FormProvider 内では useFormState を使う
import { useFormContext, useFormState } from 'react-hook-form';

function SomeField() {
  const { register, control } = useFormContext<FormValues>();
  const { errors } = useFormState({ control }); // ← この方法が推奨
  // ...
}
```

