## 7. useFieldArray — 動的フィールド

### 基本パターン

```tsx
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const OrderSchema = z.object({
  items: z
    .array(
      z.object({
        productId: z.string().min(1, '商品を選択してください'),
        quantity: z.coerce.number().int().min(1, '1以上を入力してください'),
      })
    )
    .min(1, '商品を1つ以上追加してください'),
});

type OrderFormValues = z.infer<typeof OrderSchema>;

function OrderForm() {
  const { register, control, handleSubmit, formState: { errors } } =
    useForm<OrderFormValues>({
      resolver: zodResolver(OrderSchema),
      defaultValues: {
        items: [{ productId: '', quantity: 1 }], // 初期値は必ず空のオブジェクトで
      },
    });

  const { fields, append, remove, swap, move } = useFieldArray({
    control,
    name: 'items',
  });

  return (
    <form onSubmit={handleSubmit(console.log)}>
      {fields.map((field, index) => (
        // ✅ key は field.id を使う（index はNG: 順序変更時に問題が起きる）
        <div key={field.id}>
          <select {...register(`items.${index}.productId` as const)}>
            <option value="">選択してください</option>
            <option value="p1">商品A</option>
          </select>
          {errors.items?.[index]?.productId && (
            <p role="alert">{errors.items[index].productId.message}</p>
          )}

          <input
            {...register(`items.${index}.quantity` as const)}
            type="number"
            min={1}
          />

          <button type="button" onClick={() => remove(index)}>
            削除
          </button>
        </div>
      ))}

      {/* ✅ append には defaultValues を必ず渡す（空オブジェクト {} はNG）*/}
      <button
        type="button"
        onClick={() => append({ productId: '', quantity: 1 })}
      >
        商品を追加
      </button>

      {errors.items?.root && (
        <p role="alert">{errors.items.root.message}</p>
      )}

      <button type="submit">注文する</button>
    </form>
  );
}
```

---

### ネストした useFieldArray

```tsx
// 親フィールド配列の中に子フィールド配列がある場合
function NestedFieldArrayForm() {
  const { control, register } = useForm<NestedFormValues>();

  const { fields: sections, append: appendSection } = useFieldArray({
    control,
    name: 'sections',
  });

  return (
    <>
      {sections.map((section, sectionIndex) => (
        <SectionFields
          key={section.id}
          control={control}
          register={register}
          sectionIndex={sectionIndex}
        />
      ))}
    </>
  );
}

function SectionFields({ control, register, sectionIndex }) {
  const { fields: items, append: appendItem } = useFieldArray({
    control,
    // ✅ ネストの場合は as const でキャストする
    name: `sections.${sectionIndex}.items` as const,
  });

  return (
    <div>
      {items.map((item, itemIndex) => (
        <input
          key={item.id}
          {...register(`sections.${sectionIndex}.items.${itemIndex}.value` as const)}
        />
      ))}
      <button type="button" onClick={() => appendItem({ value: '' })}>
        アイテムを追加
      </button>
    </div>
  );
}
```

