## 9. 条件付きフィールド・依存バリデーション

### 9-1. watch で条件付き表示

```tsx
function ShippingForm() {
  const { register, watch, unregister, formState: { errors } } = useForm<ShippingValues>({
    defaultValues: { deliveryType: 'standard', expressOptions: undefined },
    shouldUnregister: true, // ✅ 非表示になったフィールドは自動登録解除
  });

  const deliveryType = watch('deliveryType');

  return (
    <form>
      <select {...register('deliveryType')}>
        <option value="standard">通常配送</option>
        <option value="express">速達</option>
        <option value="pickup">店舗受け取り</option>
      </select>

      {/* ✅ 条件付きレンダリング: shouldUnregister: true なら自動クリーンアップ */}
      {deliveryType === 'express' && (
        <div>
          <label>速達オプション</label>
          <select {...register('expressOptions.timeSlot')}>
            <option value="morning">午前中</option>
            <option value="afternoon">午後</option>
          </select>
        </div>
      )}

      {deliveryType === 'pickup' && (
        <div>
          <label>受け取り店舗</label>
          <select {...register('pickupStore')}>
            <option value="store1">新宿店</option>
            <option value="store2">渋谷店</option>
          </select>
        </div>
      )}
    </form>
  );
}
