## 10. ウィザード形式・マルチステップフォーム

```tsx
// ✅ FormProvider で全ステップを一つの form インスタンスで管理
import { useForm, FormProvider } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';

const WizardSchema = z.object({
  // Step 1
  name: z.string().min(1),
  email: z.email(),
  // Step 2
  address: z.string().min(1),
  city: z.string().min(1),
  // Step 3
  cardNumber: z.string().length(16),
  expiry: z.string(),
});

// ステップごとにバリデーションするフィールドを定義
const STEP_FIELDS = {
  1: ['name', 'email'] as const,
  2: ['address', 'city'] as const,
  3: ['cardNumber', 'expiry'] as const,
};

function CheckoutWizard() {
  const [step, setStep] = useState(1);

  const methods = useForm<WizardFormValues>({
    resolver: zodResolver(WizardSchema),
    defaultValues: { name: '', email: '', address: '', city: '', cardNumber: '', expiry: '' },
    mode: 'onBlur',
  });

  const nextStep = async () => {
    // ✅ 現在のステップのフィールドだけをバリデーション
    const fields = STEP_FIELDS[step as keyof typeof STEP_FIELDS];
    const isValid = await methods.trigger(fields as any);
    if (isValid) setStep((s) => s + 1);
  };

  const onSubmit = methods.handleSubmit(async (data) => {
    await submitOrder(data);
  });

  return (
    <FormProvider {...methods}>
      <form onSubmit={onSubmit}>
        {step === 1 && <Step1 />}
        {step === 2 && <Step2 />}
        {step === 3 && <Step3 />}

        <div>
          {step > 1 && (
            <button type="button" onClick={() => setStep((s) => s - 1)}>
              戻る
            </button>
          )}
          {step < 3 ? (
            <button type="button" onClick={nextStep}>
              次へ
            </button>
          ) : (
            <button type="submit" disabled={methods.formState.isSubmitting}>
              注文を確定する
            </button>
          )}
        </div>
      </form>
    </FormProvider>
  );
}
```

