## 11. 再利用可能なフィールドコンポーネント設計

### 汎用 TextField コンポーネント

```tsx
// components/form/TextField.tsx
import { useFormContext, useFormState, FieldPath, FieldValues } from 'react-hook-form';

interface TextFieldProps<T extends FieldValues> {
  name: FieldPath<T>;
  label: string;
  placeholder?: string;
  type?: 'text' | 'email' | 'password' | 'number' | 'tel';
  required?: boolean;
  className?: string;
}

export function TextField<T extends FieldValues>({
  name,
  label,
  placeholder,
  type = 'text',
  required,
  className,
}: TextFieldProps<T>) {
  const { register, control } = useFormContext<T>();
  const { errors } = useFormState({ control });
  const error = errors[name] as { message?: string } | undefined;

  return (
    <div className={className}>
      <label htmlFor={String(name)}>
        {label}
        {required && <span aria-label="必須"> *</span>}
      </label>
      <input
        {...register(name)}
        id={String(name)}
        type={type}
        placeholder={placeholder}
        aria-invalid={!!error}
        aria-describedby={error ? `${String(name)}-error` : undefined}
        aria-required={required}
      />
      {error?.message && (
        <p id={`${String(name)}-error`} role="alert" className="text-red-500 text-sm">
          {error.message}
        </p>
      )}
    </div>
  );
}
```

