## 12. formState の活用

### 利用可能なプロパティと用途

```tsx
const {
  formState: {
    errors,          // バリデーションエラー
    isSubmitting,    // 送信中: true（ボタン無効化に使う）
    isSubmitted,     // 一度でも送信された: true
    isSubmitSuccessful, // 送信成功: true
    isDirty,         // 初期値から変更された: true（未保存警告に使う）
    dirtyFields,     // 変更されたフィールドのマップ
    isValid,         // 全バリデーション通過: true
    isValidating,    // バリデーション中（非同期）
    touchedFields,   // タッチされたフィールドのマップ
    submitCount,     // 送信試行回数
  }
} = useForm();
```

---

### 実践的な活用例

```tsx
function SmartForm() {
  const router = useRouter();
  const {
    handleSubmit,
    formState: { isDirty, isSubmitting, isSubmitSuccessful },
  } = useForm<FormValues>({ ... });

  // ✅ 未保存変更がある場合にページ離脱を警告
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (isDirty) {
        e.preventDefault();
        e.returnValue = '';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [isDirty]);

  // ✅ 送信成功後に自動でリダイレクト
  useEffect(() => {
    if (isSubmitSuccessful) {
      router.push('/success');
    }
  }, [isSubmitSuccessful, router]);

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      {/* ... */}
      <button type="submit" disabled={isSubmitting || !isDirty}>
        {isSubmitting ? '保存中...' : isDirty ? '変更を保存' : '変更なし'}
      </button>
    </form>
  );
}
```

