### 5-4. 外部 API レスポンスのバリデーション

外部 API は変更されうるため、必ず境界でバリデーションする。

```ts
// services/github.ts
const GitHubUserSchema = z.object({
  id: z.number(),
  login: z.string(),
  name: z.string().nullable(),
  email: z.string().nullable(),
  avatar_url: z.string().url(),
  public_repos: z.number(),
}).transform((data) => ({
  // アプリ内の命名規則に変換
  id: data.id,
  username: data.login,
  name: data.name,
  email: data.email,
  avatarUrl: data.avatar_url,
  publicRepos: data.public_repos,
}));

async function getGitHubUser(username: string) {
  const res = await fetch(`https://api.github.com/users/${username}`);
  const json = await res.json();

  const result = GitHubUserSchema.safeParse(json);
  if (!result.success) {
    // 外部 API の変更を早期検知
    throw new Error(`GitHub API response changed: ${result.error.message}`);
  }
  return result.data; // 型付き・変換済みデータ
}
```

