## 6. Shared スキーマ設計パターン

### 6-1. モノレポ構成でのスキーマ共有

フロントエンドとバックエンドで同じスキーマを共有することで、型の二重管理を防ぐ。

```
packages/
├── shared/           ← スキーマパッケージ
│   ├── schemas/
│   │   ├── primitives.ts   # 共通プリミティブ型
│   │   ├── users.ts        # ユーザー関連スキーマ
│   │   ├── posts.ts        # 投稿関連スキーマ
│   │   └── api/
│   │       ├── users.ts    # API リクエスト/レスポンス
│   │       └── posts.ts
│   └── index.ts            # 全スキーマの re-export
│
├── backend/
│   ├── db/schema.ts        # Drizzle スキーマ（DB 固有）
│   └── ...                 # @shared を import
│
└── frontend/
    └── ...                 # @shared を import（同じ型・バリデーション）
```

---

### 6-2. createSchemas パターン（CRUD 全操作を一括管理）

```ts
// packages/shared/schemas/utils.ts

import { z } from 'zod';

/**
 * ベーススキーマから CRUD 用の全スキーマを一括生成するファクトリ
 */
export function createCrudSchemas<T extends z.ZodObject<z.ZodRawShape>>(
  baseSchema: T,
  options: {
    omitFromCreate?: Array<keyof z.infer<T>>;
    omitFromUpdate?: Array<keyof z.infer<T>>;
    omitFromClient?: Array<keyof z.infer<T>>;
  } = {}
) {
  const { omitFromCreate = [], omitFromUpdate = [], omitFromClient = [] } = options;

  const createOmit = Object.fromEntries(omitFromCreate.map((k) => [k, true])) as any;
  const updateOmit = Object.fromEntries(omitFromUpdate.map((k) => [k, true])) as any;
  const clientOmit = Object.fromEntries(omitFromClient.map((k) => [k, true])) as any;

  return {
    /** DB から取得した全フィールド */
    db: baseSchema,
    /** クライアントに返す型（機密情報除外） */
    client: baseSchema.omit(clientOmit),
    /** 新規作成リクエスト */
    create: baseSchema.omit(createOmit),
    /** 更新リクエスト（全フィールドをオプション化） */
    update: baseSchema.omit(updateOmit).partial(),
  };
}
```

```ts
// packages/shared/schemas/users.ts
import { z } from 'zod';
import { createCrudSchemas } from './utils';

const UserBaseSchema = z.object({
  id: z.number().int().positive(),
  email: z.email(),
  name: z.string().min(1).max(100),
  bio: z.string().max(500).optional(),
  role: z.enum(['admin', 'user']),
  createdAt: z.date(),
  updatedAt: z.date(),
});

export const userSchemas = createCrudSchemas(UserBaseSchema, {
  omitFromCreate: ['id', 'createdAt', 'updatedAt', 'role'], // サーバー側で設定
  omitFromUpdate: ['id', 'email', 'createdAt', 'updatedAt', 'role'], // 変更不可フィールド
  omitFromClient: [], // 全フィールド返す（機密情報なし）
});

// 使いやすいエイリアスを export
export const {
  db: UserDbSchema,
  client: UserClientSchema,
  create: CreateUserSchema,
  update: UpdateUserSchema,
} = userSchemas;

export type User = z.infer<typeof UserClientSchema>;
export type CreateUser = z.infer<typeof CreateUserSchema>;
export type UpdateUser = z.infer<typeof UpdateUserSchema>;
```

