## 8. 高度なバリデーション

### 8-1. .refine() vs .check() — カスタムバリデーション

```ts
// v4: .superRefine() は非推奨、.check() を使う
// シンプルな条件チェック: .refine()
const PasswordSchema = z.string()
  .min(8)
  .refine(
    (val) => /[A-Z]/.test(val) && /[0-9]/.test(val),
    { error: 'パスワードは大文字と数字を含む必要があります' }
  );

// 複数条件チェックや path 指定: .check()
const ChangePasswordSchema = z.object({
  currentPassword: z.string(),
  newPassword: PasswordSchema,
  confirmPassword: z.string(),
}).check((ctx) => {
  if (ctx.value.newPassword !== ctx.value.confirmPassword) {
    ctx.issues.push({
      code: 'custom',
      message: 'パスワードが一致しません',
      path: ['confirmPassword'],
    });
  }
});
```

---

### 8-2. Discriminated Union — 多態的なデータ構造

```ts
// イベントシステム・状態マシン・API レスポンスの多態性に最適
const NotificationSchema = z.discriminatedUnion('type', [
  z.object({
    type: z.literal('email'),
    to: z.email(),
    subject: z.string(),
    body: z.string(),
  }),
  z.object({
    type: z.literal('push'),
    deviceToken: z.string(),
    title: z.string(),
    body: z.string(),
  }),
  z.object({
    type: z.literal('sms'),
    phoneNumber: z.string(),
    message: z.string().max(160),
  }),
]);

type Notification = z.infer<typeof NotificationSchema>;

// type フィールドで TypeScript が型を自動絞り込み
function send(notification: Notification) {
  switch (notification.type) {
    case 'email':
      // notification.to, .subject にアクセス可能
      break;
    case 'push':
      // notification.deviceToken にアクセス可能
      break;
  }
}
```

