## 9. エラーハンドリング

### 9-1. safeParse vs parse の使い分け

```ts
// ✅ parse: エラーを例外として扱う（信頼できるデータ、テスト）
const user = UserSchema.parse(data); // 失敗時は ZodError をスロー

// ✅ safeParse: エラーをオブジェクトとして扱う（API 境界、ユーザー入力）
const result = UserSchema.safeParse(data);
if (!result.success) {
  // result.error は ZodError
  console.log(result.error.issues); // v4: .errors → .issues
  return;
}
const user = result.data; // 型付き
```

---

### 9-2. エラーメッセージのユーザーフレンドリー化

```ts
import { z } from 'zod';

// v4: message → error パラメータ（message も後方互換あり）
const UserSchema = z.object({
  name: z.string({
    error: (issue) =>
      issue.input === undefined ? '名前は必須です' : '名前は文字列で入力してください',
  }).min(1, { error: '名前を入力してください' }).max(50, { error: '名前は50文字以内で入力してください' }),
  email: z.email({ error: '有効なメールアドレスを入力してください' }),
  age: z.number().int().min(0, { error: '年齢は0以上である必要があります' }).max(150),
});
```

---

### 9-3. エラーを API レスポンスに変換

```ts
import { z } from 'zod';

// ZodError をフロントエンドが扱いやすい形に変換
function formatZodError(error: z.ZodError) {
  return {
    code: 'VALIDATION_ERROR',
    message: 'バリデーションエラーが発生しました',
    details: error.issues.reduce(
      (acc, issue) => {
        const path = issue.path.join('.');
        if (!acc[path]) acc[path] = [];
        acc[path].push(issue.message);
        return acc;
      },
      {} as Record<string, string[]>
    ),
  };
}

// Hono でのエラーハンドラ
app.onError((err, c) => {
  if (err instanceof z.ZodError) {
    return c.json(formatZodError(err), 400);
  }
  return c.json({ code: 'INTERNAL_ERROR', message: 'サーバーエラー' }, 500);
});
```

