### 10-4. @zod/mini（フロントエンド向け軽量版）

```ts
// v4 新機能: フロントエンドではバンドルサイズを削減できる
// import { z } from 'zod';       // フル版: ~14KB gzip
// import { z } from 'zod/mini';  // Mini 版: ~6KB gzip（tree-shakable）

// Mini は zod の API サブセット。フォームバリデーションに十分
import { z } from 'zod/mini';

const FormSchema = z.object({
