### 7.3 トランザクション境界

複数 repository 更新を一つの整合性単位として扱う場合、transaction は service 層に置きます。

```ts
export const createOrder = async (input: CreateOrderInput) => {
  return db.transaction(async (tx) => {
    const order = await orderRepository.create(tx, input);
    await inventoryRepository.reserve(tx, input.items);
    await eventRepository.append(tx, {
      type: "ORDER_CREATED",
      orderId: order.id,
    });
    return order;
  });
};
```

